int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, qn;
    cin >> n >> qn;
    vector<vector<int>> graph(n);
    for (int i = 0; i < n - 1; ++i) {
        int a, b;
        cin >> a >> b;
        --a; --b;
        graph[a].push_back(b);
        graph[b].push_back(a);
    }
    vector<int> depth(n, -1);
    queue<int> q;
    depth[0] = 0;
    q.push(0);
    while (!q.empty()) {
        int v = q.front();
        q.pop();
        for (int to : graph[v]) if (depth[to] == -1) {
            depth[to] = depth[v] + 1;
            q.push(to);
        }
    }
    while (qn--) {
        int u, v;
        cin >> u >> v;
        --u; --v;
        cout << ((depth[u] + depth[v]) % 2 == 0 ? "Town" : "Road") << '\n';
    }
    return 0;
}

