long long buildNumber(vector<int> digits) {
    sort(digits.rbegin(), digits.rend());
    long long value = 0;
    for (int d : digits) value = value * 10 + d;
    return value;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;
    int n = s.size();
    long long ans = 0;
    for (int mask = 1; mask < (1 << n) - 1; ++mask) {
        vector<int> a, b;
        for (int i = 0; i < n; ++i) {
            if (mask >> i & 1) a.push_back(s[i] - '0');
            else b.push_back(s[i] - '0');
        }
        ans = max(ans, buildNumber(a) * buildNumber(b));
    }
    cout << ans << '\n';
    return 0;
}

