int result(char a, char b) {
    if (a == b) return 0;
    if ((a == 'G' && b == 'C') || (a == 'C' && b == 'P') || (a == 'P' && b == 'G')) return 1;
    return -1;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<string> hand(2 * n);
    for (string& s : hand) cin >> s;
    vector<int> win(2 * n, 0), order(2 * n);
    iota(order.begin(), order.end(), 0);
    for (int round = 0; round < m; ++round) {
        for (int i = 0; i < n; ++i) {
            int a = order[2 * i], b = order[2 * i + 1];
            int r = result(hand[a][round], hand[b][round]);
            if (r == 1) ++win[a];
            else if (r == -1) ++win[b];
        }
        sort(order.begin(), order.end(), [&](int a, int b) {
            if (win[a] != win[b]) return win[a] > win[b];
            return a < b;
        });
    }
    for (int id : order) cout << id + 1 << '\n';
    return 0;
}

