    double totalTime = 0.0;
    for (int i = 0; i < n; ++i) {
        cin >> a[i] >> b[i];
        totalTime += a[i] / b[i];
    }
    double remain = totalTime / 2.0;
    double ans = 0.0;
    for (int i = 0; i < n; ++i) {
        double t = a[i] / b[i];
