int n;
long long x;
vector<vector<long long>> bags;

long long dfs(int idx, long long product) {
    if (idx == n) return product == x ? 1 : 0;
    long long res = 0;
    for (long long v : bags[idx]) {
        if (product > x / v) continue;
        res += dfs(idx + 1, product * v);
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n >> x;
    bags.resize(n);
    for (int i = 0; i < n; ++i) {
        int l;
        cin >> l;
        bags[i].resize(l);
        for (long long& v : bags[i]) cin >> v;
    }
    cout << dfs(0, 1) << '\n';
    return 0;
}

